124			return
125		}
126	
127		rawSections, err := unmarshalSections(row.Sections)
128		if err != nil {
129			log.Printf("unmarshal sections error: %v", err)
130			response.WriteInternalServerErrorResponse(w)
131			return
132		}
133	
134		_ = json.NewEncoder(w).Encode(GetEnrollmentResponse{
135			CourseId:  courseID.String(),
136			Title:     row.Title,
137			Sections:  buildSections(rawSections),
138			NextTopic: decideNextTopic(rawSections),
139		})
140	}
