142	func unmarshalSections(raw []byte) ([]rawSection, error) {
143		if len(raw) == 0 {
144			return nil, nil
145		}
146		var sections []rawSection
147		if err := json.Unmarshal(raw, &sections); err != nil {
148			return nil, err
149		}
150		return sections, nil
151	}
