153	func buildSections(rawSecs []rawSection) []getEnrollmentSectionResponse {
154		sections := make([]getEnrollmentSectionResponse, 0, len(rawSecs))
155		for _, rs := range rawSecs {
156			topics := make([]getEnrollmentTopicResponse, 0, len(rs.Topics))
157			for _, rt := range rs.Topics {
158				topics = append(topics, getEnrollmentTopicResponse{
159					TopicId: rt.TopicId,
160					Title:   rt.Title,
161					Status:  rt.Status,
162				})
163			}
164			sections = append(sections, getEnrollmentSectionResponse{
165				SectionId: rs.SectionId,
166				Title:     rs.Title,
167				Topics:    topics,
168			})
169		}
170		return sections
171	}
172	
173	// decideNextTopic は section/topic の index ASC 順に並んだ rawSection から、
174	// 次に取るべき topic を course.entity.go の findTopicToStart/nextTopic 踏襲で決定する。
175	//   - 全 NOT_STARTED                                  -> 先頭トピック
176	//   - (sec_idx, top_idx) 最大の非 NOT_STARTED が IN_PROGRESS -> その topic
177	//   - 同上が COMPLETED かつ次の topic がある           -> 次の topic
178	//   - 同上が COMPLETED かつ最終位置 (= 全完了)         -> nil
179	func decideNextTopic(rawSecs []rawSection) *getEnrollmentNextTopicResponse {
180		if len(rawSecs) == 0 {
181			return nil
182		}
183	
184		lastSecIdx, lastTopIdx := -1, -1
