1	package commands
2	
3	import (
4		"errors"
5		"time"
6	
7		"github.com/google/uuid"
8	)
9	
10	var (
11		ErrAlreadyEnrolled      = errors.New("already enrolled")
12		ErrNotEnrolled          = errors.New("not enrolled")
13		ErrTopicNotInEnrollment = errors.New("topic not in enrollment")
14		ErrInvalidStatusTransit = errors.New("invalid progress status transition")
15	)
16	
17	// Enrollment は (userId, courseId) を自然キーとする集約ルート。
18	type Enrollment struct {
19		userId          uuid.UUID
20		courseId        uuid.UUID
21		enrolledAt      time.Time
22		topicProgresses []TopicProgress
23	}
24	
25	type TopicProgress struct {
26		topicId uuid.UUID
27		status  ProgressStatus
28	}
29	
30	func NewEnrollment(userId, courseId uuid.UUID, enrolledAt time.Time) Enrollment {
31		return Enrollment{
32			userId:          userId,
33			courseId:        courseId,
34			enrolledAt:      enrolledAt,
35			topicProgresses: []TopicProgress{},
36		}
37	}
38	
39	// ReconstructEnrollment は永続化層から取得した値で Enrollment を再構築する。
40	// ドメイン外（リポジトリ）からの利用のみを想定。
41	func ReconstructEnrollment(
42		userId, courseId uuid.UUID,
43		enrolledAt time.Time,
44		topicProgresses []TopicProgress,
45	) Enrollment {
46		if topicProgresses == nil {
47			topicProgresses = []TopicProgress{}
48		}
49		return Enrollment{
50			userId:          userId,
51			courseId:        courseId,
52			enrolledAt:      enrolledAt,
53			topicProgresses: topicProgresses,
54		}
55	}
56	
57	func ReconstructTopicProgress(topicId uuid.UUID, status ProgressStatus) TopicProgress {
58		return TopicProgress{topicId: topicId, status: status}
59	}
60	
61	func (e Enrollment) UserId() uuid.UUID     { return e.userId }
62	func (e Enrollment) CourseId() uuid.UUID   { return e.courseId }
63	func (e Enrollment) EnrolledAt() time.Time { return e.enrolledAt }
64	func (e Enrollment) TopicProgresses() []TopicProgress {
65		out := make([]TopicProgress, len(e.topicProgresses))
66		copy(out, e.topicProgresses)
67		return out
68	}
69	
70	func (p TopicProgress) TopicId() uuid.UUID     { return p.topicId }
71	func (p TopicProgress) Status() ProgressStatus { return p.status }
72	
73	// UpdateTopicProgress は集約内のトピック進捗を更新する。
74	// 既存進捗が無ければ新規追加、あれば状態遷移ルールを検証して更新する。
75	// 戻り値は更新後の TopicProgress。
76	func (e *Enrollment) UpdateTopicProgress(topicId uuid.UUID, status ProgressStatus) (TopicProgress, error) {
77		if !status.isValid() {
78			return TopicProgress{}, ErrInvalidProgressStatus
79		}
80	
81		for i, tp := range e.topicProgresses {
82			if tp.topicId != topicId {
83				continue
84			}
85			if !tp.status.canTransitTo(status) {
86				return TopicProgress{}, ErrInvalidStatusTransit
87			}
88			e.topicProgresses[i].status = status
89			return e.topicProgresses[i], nil
90		}
91	
92		tp := TopicProgress{topicId: topicId, status: status}
93		e.topicProgresses = append(e.topicProgresses, tp)
94		return tp, nil
95	}
