}

func (r *SqrcEnrollmentRepository) findByUserAndCourse(ctx context.Context, userId, courseId uuid.UUID) (Enrollment, error) {
	userIdUuid, err := toPgUUID(userId)
	if err != nil {
		return Enrollment{}, err
	}
	courseIdUuid, err := toPgUUID(courseId)
	if err != nil {
		return Enrollment{}, err
