"use client";

import { useState, type JSX } from "react";
import { Button } from "@/components/ui/button";
import { useIsHydrated } from "@/hooks/use-is-hydrated";

interface Props {
  authorSlug: string;
  courseSlug: string;
}

export function EnrollCommandBlock({
  authorSlug,
  courseSlug,
}: Props): JSX.Element {
  const command = `/jukubox enroll ${authorSlug}/${courseSlug}`;
  const [copied, setCopied] = useState(false);
  const isHydrated = useIsHydrated();

  async function handleCopy(): Promise<void> {
    await navigator.clipboard.writeText(command);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  }

  return (
    <div className="flex flex-col gap-2">
      <p className="text-sm text-muted-foreground">
        受講を開始するには Claude Code で以下のコマンドを実行してください
      </p>
      <div className="flex items-stretch gap-2">
        <code className="flex-1 truncate rounded-md border border-border bg-muted px-3 py-2 font-mono text-sm">
          {command}
        </code>
        <Button
          variant="outline"
          size="sm"
          onClick={handleCopy}
          disabled={!isHydrated}
        >
          {copied ? "コピーしました" : "コピー"}
        </Button>
      </div>
    </div>
  );
}

