import type { JSX } from "react";
import { Skeleton } from "@/components/ui/skeleton";

const SECTION_COUNT = 3;
const TOPIC_PER_SECTION = 2;

export function CourseDetailSkeleton(): JSX.Element {
  return (
    <div className="flex flex-col gap-6">
      <div className="flex flex-col gap-3">
        <Skeleton className="h-6 w-3/4" />
        <Skeleton className="h-4 w-full" />
        <Skeleton className="h-4 w-5/6" />
      </div>
      <Skeleton className="h-12 w-full" />
      <ul className="flex flex-col gap-4">
        {Array.from({ length: SECTION_COUNT }, (_, sectionIndex) => (
          <li
            // biome-ignore lint/suspicious/noArrayIndexKey: 静的個数のスケルトン
            key={sectionIndex}
            className="rounded-md border border-border bg-card p-4"
          >
            <Skeleton className="mb-2 h-5 w-2/3" />
            <Skeleton className="mb-3 h-3 w-1/2" />
            <ul className="flex flex-col gap-2 pl-3">
              {Array.from({ length: TOPIC_PER_SECTION }, (_, topicIndex) => (
                <li
                  // biome-ignore lint/suspicious/noArrayIndexKey: 静的個数のスケルトン
                  key={topicIndex}
                  className="flex flex-col gap-1"
                >
                  <Skeleton className="h-4 w-1/3" />
                  <Skeleton className="h-3 w-1/2" />
                </li>
              ))}
            </ul>
          </li>
        ))}
      </ul>
    </div>
  );
}

