import type { JSX } from "react";
import { Badge } from "@/components/ui/badge";
import type { CourseDetail } from "./course-detail.data";
import { EnrollCommandBlock } from "./enroll-command-block.universal";
import { EnrolledBadge } from "./enrolled-badge.universal";

interface Props {
  course: CourseDetail;
}

export function CourseDetailPresenter({ course }: Props): JSX.Element {
  return (
    <article className="flex flex-col gap-6">
      <header className="flex flex-col gap-3">
        <div className="flex items-center gap-3">
          <h1 className="text-2xl font-bold text-foreground">{course.title}</h1>
          {course.isEnrolled ? <EnrolledBadge /> : null}
        </div>
        <p className="text-sm text-muted-foreground">講師: {course.author.name}</p>
        {course.description ? (
          <p className="whitespace-pre-wrap text-sm text-foreground">
            {course.description}
          </p>
        ) : null}
        {course.tags.length > 0 ? (
          <ul className="flex flex-wrap gap-1">
            {course.tags.map((tag) => (
              <li key={tag}>
                <Badge variant="outline">{tag}</Badge>
              </li>
            ))}
          </ul>
        ) : null}
      </header>

      <EnrollCommandBlock
        authorSlug={course.author.slug}
        courseSlug={course.slug}
      />

      <section className="flex flex-col gap-3">
        <h2 className="text-lg font-bold text-foreground">講座構成</h2>
        {course.sections.length === 0 ? (
          <p className="text-sm text-muted-foreground">
            この講座にはまだセクションがありません
          </p>
        ) : (
          <ol className="flex flex-col gap-3">
            {course.sections.map((section) => (
              <li
                key={section.sectionId}
                className="rounded-md border border-border bg-card p-4"
              >
                <h3 className="text-base font-bold text-foreground">
                  {section.title}
                </h3>
                {section.description ? (
                  <p className="mt-1 text-xs text-muted-foreground">
                    {section.description}
                  </p>
                ) : null}
                {section.topics.length > 0 ? (
                  <ul className="mt-3 flex flex-col gap-2 pl-3">
                    {section.topics.map((topic) => (
                      <li key={topic.topicId} className="flex flex-col">
                        <span className="text-sm font-medium text-foreground">
                          {topic.title}
                        </span>
                        {topic.description ? (
                          <span className="text-xs text-muted-foreground">
                            {topic.description}
                          </span>
                        ) : null}
                      </li>
                    ))}
                  </ul>
                ) : null}
              </li>
            ))}
          </ol>
        )}
      </section>
    </article>
  );
}

