        >
          <HugeiconsIcon icon={HelpCircleIcon} className="size-4" />
          <span className="sr-only">受講開始方法の説明</span>
        </Link>
      </div>
      <div className="grid grid-cols-[1fr_auto] items-stretch gap-2">
        <Input
          id={commandInputId}
          value={command}
          readOnly
          className="font-mono text-xs"
        />
        <CopyButton text={command} />
      </div>
    </div>
  );
}

