package commands

import (
	"errors"

	"github.com/google/uuid"
)

type Topic struct {
	topicId     string
	title       string
	description string
	content     string
	number      int
}

type Section struct {
	sectionId   string
	title       string
	description string
	number      int
	topics      []Topic
}

type Author struct {
	authorId string
	name     string
}

type Category struct {
	categoryId string
	name       string
}

type Course struct {
	courseId      string
	title         string
	description   string
	slug          string
	tags          []string
	publishStatus string
	category      Category
	publishedAt   *string
	author        Author
	visibility    string
	sections      []Section
}

var ErrEnrollmentNotAllowed = errors.New("enrollment not allowed")
var ErrTopicNotFoundInCourse = errors.New("topic not found in course")

func (course *Course) checkEnrollable(userId uuid.UUID) error {
	if course.publishStatus != "published" && course.author.authorId != userId.String() {
		return ErrEnrollmentNotAllowed
	}
	return nil
}

func (course *Course) findTopicById(topicId uuid.UUID) (Topic, error) {
	for _, section := range course.sections {
		for _, topic := range section.topics {
			if topic.topicId == topicId.String() {
				return topic, nil
			}
		}
	}
	return Topic{}, ErrTopicNotFoundInCourse
}

package commands

import (
	"context"
	"encoding/json"
	"time"

	"github.com/google/uuid"
	"github.com/harusame0616/ijuku/apps/api/internal/db"
	"github.com/jackc/pgx/v5/pgtype"
)

type SqrcCourseRepository struct {
	sqrc db.Querier
}

func NewSqrcCourseRepository(q db.Querier) *SqrcCourseRepository {
	return &SqrcCourseRepository{sqrc: q}
}

func (repository *SqrcCourseRepository) getCourseByCourseId(ctx context.Context, courseId uuid.UUID) (Course, error) {
	var courseIdUuid pgtype.UUID

	if err := courseIdUuid.Scan(courseId.String()); err != nil {
		return Course{}, err
	}

	courseRaw, err := repository.sqrc.GetCourseById(ctx, courseIdUuid)
	if err != nil {
		return Course{}, err
	}

	return toCourseFromIdRow(courseRaw), nil
}

func (repository *SqrcCourseRepository) getCourseBySlug(ctx context.Context, authorSlug, courseSlug string) (Course, error) {
	courseRaw, err := repository.sqrc.GetCourseBySlug(ctx, db.GetCourseBySlugParams{
		Authorslug: authorSlug,
		Courseslug: courseSlug,
	})
	if err != nil {
		return Course{}, err
	}

	return toCourseFromSlugRow(courseRaw), nil
}

func toCourseFromIdRow(raw db.GetCourseByIdRow) Course {
	return buildCourse(courseRawFields{
		CourseID:      raw.CourseID,
		Title:         raw.Title,
		Description:   raw.Description,
		Slug:          raw.Slug,
		Tags:          raw.Tags,
		PublishStatus: raw.PublishStatus,
		CategoryID:    raw.CategoryID,
		CategoryName:  raw.CategoryName,
		PublishedAt:   raw.PublishedAt,
		AuthorID:      raw.AuthorID,
		AuthorName:    raw.AuthorName,
		Visibility:    raw.Visibility,
		Sections:      raw.Sections,
	})
}

func toCourseFromSlugRow(raw db.GetCourseBySlugRow) Course {
	return buildCourse(courseRawFields{
		CourseID:      raw.CourseID,
		Title:         raw.Title,
		Description:   raw.Description,
		Slug:          raw.Slug,
		Tags:          raw.Tags,
		PublishStatus: raw.PublishStatus,
		CategoryID:    raw.CategoryID,
		CategoryName:  raw.CategoryName,
		PublishedAt:   raw.PublishedAt,
		AuthorID:      raw.AuthorID,
		AuthorName:    raw.AuthorName,
		Visibility:    raw.Visibility,
		Sections:      raw.Sections,
	})
}

type courseRawFields struct {
	CourseID      pgtype.UUID
	Title         string
	Description   string
	Slug          string
	Tags          []byte
	PublishStatus string
	CategoryID    pgtype.UUID
	CategoryName  string
	PublishedAt   pgtype.Timestamptz
	AuthorID      pgtype.UUID
	AuthorName    string
	Visibility    string
	Sections      []byte
}

func buildCourse(raw courseRawFields) Course {
	var tags []string
	json.Unmarshal(raw.Tags, &tags)

	type topicRaw struct {
		CourseSectionTopicId string `json:"course_section_topic_id"`
		Title                string `json:"title"`
		Description          string `json:"description"`
		Content              string `json:"content"`
	}
	type sectionRaw struct {
		CourseSectionId string     `json:"course_section_id"`
		Title           string     `json:"title"`
		Description     string     `json:"description"`
		Topics          []topicRaw `json:"topics"`
	}

	var sectionsRaw []sectionRaw
	json.Unmarshal(raw.Sections, &sectionsRaw)

	sections := make([]Section, len(sectionsRaw))
	for i, s := range sectionsRaw {
		topics := make([]Topic, len(s.Topics))
		for j, t := range s.Topics {
			topics[j] = Topic{
				topicId:     t.CourseSectionTopicId,
				title:       t.Title,
				description: t.Description,
				content:     t.Content,
				number:      j,
			}
		}
		sections[i] = Section{
			sectionId:   s.CourseSectionId,
			title:       s.Title,
			description: s.Description,
			number:      i,
			topics:      topics,
		}
	}

	var publishedAt *string
	if raw.PublishedAt.Valid {
		t := raw.PublishedAt.Time.Format(time.RFC3339)
		publishedAt = &t
	}

	return Course{
		courseId:      raw.CourseID.String(),
		title:         raw.Title,
		description:   raw.Description,
		slug:          raw.Slug,
		tags:          tags,
		publishStatus: raw.PublishStatus,
		category: Category{
			categoryId: raw.CategoryID.String(),
			name:       raw.CategoryName,
		},
		publishedAt: publishedAt,
		author: Author{
			authorId: raw.AuthorID.String(),
			name:     raw.AuthorName,
		},
		visibility: raw.Visibility,
		sections:   sections,
	}
}

