1	package commands
2	
3	import (
4		"context"
5		"time"
6	
7		"github.com/google/uuid"
8	)
9	
10	type EnrollParams struct {
11		userId     uuid.UUID
12		authorSlug string
13		courseSlug string
14	}
15	
16	type EnrollResult struct {
17		CourseId   string
18		EnrolledAt time.Time
19	}
20	
21	type EnrollCourseRepository interface {
22		getCourseBySlug(ctx context.Context, authorSlug, courseSlug string) (Course, error)
23	}
24	
25	type EnrollmentCreator interface {
26		findByUserAndCourse(ctx context.Context, userId, courseId uuid.UUID) (Enrollment, error)
27		create(ctx context.Context, enrollment Enrollment) error
28	}
29	
30	type EnrollUsecaseInterface interface {
31		execute(ctx context.Context, params EnrollParams) (EnrollResult, error)
32	}
33	
34	type EnrollUsecase struct {
35		courseRepository     EnrollCourseRepository
36		enrollmentRepository EnrollmentCreator
37		now                  func() time.Time
38	}
39	
40	func NewEnrollUsecase(courseRepo EnrollCourseRepository, enrollmentRepo EnrollmentCreator) EnrollUsecase {
41		return EnrollUsecase{
42			courseRepository:     courseRepo,
43			enrollmentRepository: enrollmentRepo,
44			now:                  time.Now,
45		}
46	}
47	
48	func (u EnrollUsecase) execute(ctx context.Context, params EnrollParams) (EnrollResult, error) {
49		course, err := u.courseRepository.getCourseBySlug(ctx, params.authorSlug, params.courseSlug)
50		if err != nil {
51			return EnrollResult{}, err
52		}
53	
54		if err := course.checkEnrollable(params.userId); err != nil {
55			return EnrollResult{}, err
56		}
57	
58		courseId, err := uuid.Parse(course.courseId)
59		if err != nil {
60			return EnrollResult{}, err
61		}
62	
63		if _, err := u.enrollmentRepository.findByUserAndCourse(ctx, params.userId, courseId); err == nil {
